  1→import { useSourceName } from "@/features/sources/hooks/useSourceName";
  2→import { useLocalizedTagLabels } from "@/features/tags/hooks/useLocalizedTagLabels";
  3→import type { RecipeMetadata } from "@/lib/types/recipe";
  4→import { LinearGradient } from "expo-linear-gradient";
  5→import { type JSX } from "react";
  6→import { Pressable, StyleSheet, Text, View } from "react-native";
  7→import { useSafeAreaInsets } from "react-native-safe-area-context";
  8→
  9→export function MetadataOverlay({
 10→  metadata,
 11→  onPress,
 12→  disabled,
 13→}: {
 14→  metadata: RecipeMetadata;
 15→  onPress?: () => void;
 16→  disabled?: boolean;
 17→}): JSX.Element | null {
 18→  const insets = useSafeAreaInsets();
 19→  const { displayName: sourceDisplayName } = useSourceName(metadata.source);
 20→  const tagLabels = useLocalizedTagLabels(metadata.tagIds);
 21→  const hasTitle = !!metadata.title;
 22→  const hasSource = !!sourceDisplayName;
 23→  const hasTags = tagLabels.length > 0;
 24→
 25→  if (!hasTitle && !hasSource && !hasTags) {
 26→    return null;
 27→  }
 28→
 29→  return (
 30→    <LinearGradient
 31→      colors={["rgba(0,0,0, 1)", "rgba(0,0,0,0.6)", "transparent"]}
 32→      locations={[0, 0.6, 1]}
 33→      style={[styles.gradient, { paddingTop: insets.top + 24 }]}
 34→      pointerEvents="box-none"
 35→    >
 36→      <Pressable
 37→        onPress={onPress}
 38→        disabled={disabled || !onPress}
 39→        style={({ pressed }) => [
 40→          styles.pressable,
 41→          { opacity: pressed ? 0.7 : 1 },
 42→        ]}
 43→        hitSlop={8}
 44→      >
 45→        {hasTitle && (
 46→          <Text style={styles.title} numberOfLines={2} ellipsizeMode="tail">
 47→            {metadata.title}
 48→          </Text>
 49→        )}
 50→        {hasSource && (
 51→          <Text style={styles.source} numberOfLines={1} ellipsizeMode="tail">
 52→            {sourceDisplayName}
 53→          </Text>
 54→        )}
 55→        {hasTags && (
 56→          <View style={styles.tagsContainer}>
 57→            <Text style={styles.tags} numberOfLines={1} ellipsizeMode="tail">
 58→              {tagLabels.join("  ")}
 59→            </Text>
 60→          </View>
 61→        )}
 62→      </Pressable>
 63→    </LinearGradient>
 64→  );
 65→}
 66→
 67→const styles = StyleSheet.create({
 68→  gradient: {
 69→    position: "absolute",
 70→    top: 0,
 71→    left: 0,
 72→    right: 0,
 73→    paddingHorizontal: 16,
 74→    paddingBottom: 80,
 75→  },
 76→  pressable: {
 77→    alignSelf: "flex-start",
 78→  },
 79→  title: {
 80→    color: "white",
 81→    fontSize: 24,
 82→    fontWeight: "bold",
